// Input from 01-whatsapp-receiver via webhook (body-wrapped) or direct
const raw = $json.body || $json;

// Detect source: if has entry[] it's direct Meta webhook, otherwise it's pre-extracted
let tel, texto, push_name, location_lat = null, location_lng = null;

if (raw.entry) {
  // Direct Meta webhook format
  const value = raw.entry?.[0]?.changes?.[0]?.value;
  const message = value?.messages?.[0];
  if (!message) return [];
  tel = message.from || '';
  push_name = value?.contacts?.[0]?.profile?.name || '';
  if (message.type === 'text') {
    texto = (message.text?.body || '').trim();
  } else if (message.type === 'interactive') {
    const ia = message.interactive;
    texto = ia?.button_reply?.id || ia?.list_reply?.id || '';
  } else if (message.type === 'location') {
    location_lat = message.location?.latitude;
    location_lng = message.location?.longitude;
    texto = '__location__';
  }
} else {
  // Pre-extracted from 01-whatsapp-receiver
  tel = raw.tel || raw.from || '';
  texto = (raw.texto || raw.text || '').trim();
  push_name = raw.push_name || '';
  location_lat = raw.location_lat || null;
  location_lng = raw.location_lng || null;
}

if (!tel) return [];
if (!texto && !location_lat) return [];

return [{ json: { tel, texto: texto.toLowerCase(), push_name, location_lat, location_lng, instancia: 'meta' } }];

const now = new Date();
const optsTime = { timeZone: 'America/Sao_Paulo', hour: '2-digit', minute: '2-digit', hour12: false };
const horaAtual = now.toLocaleTimeString('pt-BR', optsTime).substring(0, 5);
const diaBR = new Date(now.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const dias = ['dom', 'seg', 'ter', 'qua', 'qui', 'sex', 'sab'];
const diaSemana = dias[diaBR.getDay()];

return [{ json: { ...$json, horaAtual, diaSemana } }];

