}


class CartHandler extends BaseHandler {
    async handle() {
        // Repeat order — sim
        if (texto === 'sim' && currentState === BotState.REPEAT_ORDER) {
            if (lastOrder && Array.isArray(lastOrder.items)) {
                const items = lastOrder.items.map((orderItem) => {
                    const product = products.find((prod) => prod.id === orderItem.id);
                    return product ? { id: product.id, name: product.name, qty: orderItem.qty, price: Number(product.price), menuIdx: products.indexOf(product) + 1 } : null;
                }).filter(Boolean);
                newCart.items = items;
                newState = BotState.ORDERING;
                const { lines, total } = cartSummary(items);
                respostas.push(MessagesConstants.PEDIDO_REPETIDO + lines.join('\n') + '\n\n*Total: R$ ' + fmtBRL(total) + '*' + MessagesConstants.PEDIDO_REPETIDO_SUFFIX);
            }
            else {
                newState = BotState.START;
                respostas.push(MessagesConstants.PEDIDO_REPETIDO_NAO_ENCONTRADO);
            }
            return true;
        }
        // Repeat order — não
        if ((texto === 'não' || texto === 'nao') && currentState === BotState.REPEAT_ORDER) {
            newState = BotState.START;
            newCart = CartConstants.EMPTY();
            respostas.push(MessagesConstants.REPEAT_ORDER_RECUSA);
            respostas.push(mainMenu());
            return true;
        }
        // Qualquer outro texto em repeat_order
        if (currentState === BotState.REPEAT_ORDER) {
            respostas.push(yesNo(MessagesConstants.REPEAT_ORDER_PROMPT));
            return true;
        }
        // Ver carrinho
        if (texto === 'carrinho') {
            if (newCart.items.length === 0) {
                respostas.push(MessagesConstants.CARRINHO_VAZIO);
            }
            else {
                const { lines, total } = cartSummary(newCart.items);
                respostas.push(MessagesConstants.CARRINHO_RESUMO_PREFIX + lines.join('\n') + '\n\n*Total: R$ ' + fmtBRL(total) + '*' + MessagesConstants.CARRINHO_RESUMO_SUFFIX);
            }
            return true;
        }
        // Finalizar
        if (texto === 'finalizar') {
            if (newCart.items.length === 0) {
                respostas.push(MessagesConstants.CARRINHO_VAZIO);
            }
            else {
                const { lines, total } = cartSummary(newCart.items);
                const minOrder = minOrderValue;
                if (minOrder > 0 && total < minOrder) {
                    respostas.push(MessagesConstants.VALOR_MINIMO(fmtBRL(minOrder), fmtBRL(total)));
                }
                else {
                    newState = BotState.CONFIRMING;
                    respostas.push(confirmBtn(MessagesConstants.CONFIRMAR_PEDIDO(lines.join('\n'), fmtBRL(total))));
                }
            }
            return true;
        }
        // Confirmar pedido
        if ((texto === 'confirmar' || texto === 'sim') && currentState === BotState.CONFIRMING) {
            if (orderTypes.length > 1) {
                newState = BotState.AWAITING_TYPE;
                respostas.push(orderTypeBtn());
            }
            else if (featureDelivery) {
                newCart.order_type = 'delivery';
                newState = BotState.AWAITING_ADDRESS;
                respostas.push(MessagesConstants.SOLICITAR_ENDERECO);
            }
            else {
                newCart.order_type = orderTypes[0] ? orderTypes[0].name : 'retirada';
                newCart.delivery_fee = 0;
                newState = BotState.AWAITING_PAYMENT;
                respostas.push(MessagesConstants.TIPO_CONFIRMADO(orderTypes[0] ? orderTypes[0].label : 'Retirada'));
                respostas.push(paymentList(newCart.split_count));
            }
            return true;
        }
        return false;
    }
}


class DeliveryHandler extends BaseHandler {
    async handle() {
        if (currentState === BotState.AWAITING_TYPE) {
            let choiceIndex = parseInt(texto) - 1;
            if (isNaN(choiceIndex) || choiceIndex < 0)
                choiceIndex = orderTypes.findIndex((orderType) => orderType.name === texto || orderType.label.toLowerCase() === texto.toLowerCase());
            if (choiceIndex >= 0 && choiceIndex < orderTypes.length) {
                const selectedType = orderTypes[choiceIndex];
                newCart.order_type = selectedType.name;
                if (selectedType.name === 'delivery') {
                    newState = BotState.AWAITING_ADDRESS;
                    respostas.push(MessagesConstants.SOLICITAR_ENDERECO);
                }
                else {
                    newCart.delivery_fee = 0;
                    newState = BotState.AWAITING_PAYMENT;
                    respostas.push(MessagesConstants.TIPO_CONFIRMADO(selectedType.label));
                    respostas.push(paymentList(newCart.split_count));
                }
            }
            else {
                respostas.push(orderTypeBtn());
            }
            return true;
        }
        if (currentState === BotState.AWAITING_ADDRESS) {
            await this._handleAddress();
            return true;
        }
        if (currentState === BotState.AWAITING_ADDRESS_NUMBER) {
            await this._handleAddressNumber();
            return true;
        }
        if (currentState === BotState.OFFER_PICKUP) {
            if (texto === 'sim') {
                newCart.order_type = 'retirada';
                newCart.delivery_fee = 0;
                newState = BotState.AWAITING_PAYMENT;
                respostas.push(MessagesConstants.RETIRADA_CONFIRMADA);
                respostas.push(paymentList(newCart.split_count));
            }
            else {
                newState = BotState.AWAITING_ADDRESS;
                respostas.push(MessagesConstants.OUTRO_ENDERECO(estCity || ''));
            }
            return true;
        }
        return false;
    }
    _coordsConfigured() {
        return estLat !== 0 || estLng !== 0;
    }
    _buildEtaLine(calcFee, routeMin, routeKm) {
        if (routeMin <= 0)
            return '';
        return calcFee === 0
            ? MessagesConstants.ETA_LINE_GRATIS(routeMin, routeKm.toFixed(1))
            : MessagesConstants.ETA_LINE(fmtBRL(calcFee), routeMin, routeKm.toFixed(1));
    }
    async _applyRoute(lat, lng, addressLabel) {
        const distance = haversine(estLat, estLng, lat, lng);
        if (this._coordsConfigured() && distance > maxRadiusKm) {
            newCart.address = addressLabel;
            newState = BotState.OFFER_PICKUP;
            respostas.push(offerPickupBtn(MessagesConstants.ENDERECO_FORA_AREA(maxRadiusKm)));
            return;
        }
        let routeKm = 0;
        let routeMin = 0;
        if (this._coordsConfigured()) {
            const route = await routingProvider.route(estLat, estLng, lat, lng);
            if (route) {
                routeKm = route.km;
                routeMin = route.min;
            }
        }
        const { total: cartSubtotal } = cartSummary(newCart.items);
        const calcFee = calcDeliveryFee(routeKm, routeMin, cartSubtotal);
        newCart.address = addressLabel;
        newCart.delivery_fee = calcFee;
        newState = BotState.AWAITING_COMPLEMENT;
        respostas.push(locationMsg(lat, lng, 'Endereço de entrega', addressLabel));
        respostas.push(MessagesConstants.ENDERECO_ENCONTRADO(addressLabel, this._buildEtaLine(calcFee, routeMin, routeKm)));
    }
    async _handleAddress() {
        const estCity = estCity || '';
        const estCityName = estCity.split(',')[0].trim().toLowerCase();
        if (texto === '__location__' && location_lat != null && location_lng != null) {
            const lat = Number(location_lat);
            const lng = Number(location_lng);
            const distance = haversine(estLat, estLng, lat, lng);
            if (this._coordsConfigured() && distance > maxRadiusKm) {
                newCart.address = 'Localização compartilhada';
                newState = BotState.OFFER_PICKUP;
                respostas.push(offerPickupBtn(MessagesConstants.ENDERECO_FORA_AREA(maxRadiusKm)));
                return;
            }
            let routeKm = 0;
            let routeMin = 0;
            if (this._coordsConfigured()) {
                const route = await routingProvider.route(estLat, estLng, lat, lng);
                if (route) {
                    routeKm = route.km;
                    routeMin = route.min;
                }
            }
            let addressLabel = 'Localização compartilhada';
            const reverseResult = await geocodingProvider.reverse(lat, lng);
            if (reverseResult?.address) {
                const addr = reverseResult.address;
                const parts = [addr.road, addr.house_number, addr.suburb || addr.neighbourhood, addr.city || addr.town || addr.village, addr.state_code || addr.state].filter(Boolean);
                if (parts.length > 0)
                    addressLabel = parts.join(', ');
            }
            const { total: cartSubtotal } = cartSummary(newCart.items);
            const calcFee = calcDeliveryFee(routeKm, routeMin, cartSubtotal);
            newCart.address = addressLabel;
            newCart.delivery_fee = calcFee;
            newState = BotState.AWAITING_COMPLEMENT;
            respostas.push(locationMsg(lat, lng, 'Endereço de entrega', addressLabel));
            respostas.push(MessagesConstants.LOCALIZACAO_RECEBIDA(addressLabel, this._buildEtaLine(calcFee, routeMin, routeKm)));
            return;
        }
        const input = texto.trim();
        const cepDigits = input.replace(/\D/g, '');
        let addressToGeocode = input;
        let cepInfo = null;
        if (cepDigits.length === 8) {
            cepInfo = await cepProvider.lookup(cepDigits);
            const nonFormattingChars = input.replace(/[\d\s.\-]/g, '');
            const isCepOnly = nonFormattingChars.length === 0;
            if (isCepOnly && cepInfo) {
                const streetLabel = [cepInfo.logradouro, cepInfo.bairro, cepInfo.localidade, cepInfo.uf].filter(Boolean).join(', ');
                newCart.address_street_temp = JSON.stringify({
                    logradouro: cepInfo.logradouro || '',
                    bairro: cepInfo.bairro || '',
                    localidade: cepInfo.localidade || '',
                    uf: cepInfo.uf || '',
                    cep: cepInfo.cep || '',
                });
                newState = BotState.AWAITING_ADDRESS_NUMBER;
                respostas.push(MessagesConstants.CEP_ENCONTRADO(cepInfo.cep, streetLabel));
                _earlyResponse = buildPayload();
                return;
            }
            if (cepInfo) {
                const parts = [cepInfo.logradouro, cepInfo.bairro, cepInfo.localidade, cepInfo.uf].filter(Boolean);
                if (parts.length > 0)
                    addressToGeocode = parts.join(', ');
            }
        }
        const streetAndNumMatch = input.match(/^(.+?\s+\d+)/);
        const streetAndNum = streetAndNumMatch ? streetAndNumMatch[1].trim() : input;
        let geoResult = await geocodingProvider.search(addressToGeocode + ', Brasil');
        if (!geoResult && estCity && !addressToGeocode.toLowerCase().includes(estCityName)) {
            const withCity = addressToGeocode + ', ' + estCity;
            geoResult = await geocodingProvider.search(withCity + ', Brasil');
            if (geoResult)
                addressToGeocode = withCity;
        }
        if (!geoResult && estCity && streetAndNum !== addressToGeocode) {
            const stripped = streetAndNum + ', ' + estCity;
            geoResult = await geocodingProvider.search(stripped + ', Brasil');
            if (geoResult)
                addressToGeocode = stripped;
        }
        if (!geoResult) {
            const hint = cepInfo
                ? MessagesConstants.ENDERECO_HINT_CEP(cepInfo.cep, addressToGeocode)
                : MessagesConstants.ENDERECO_HINT(estCity);
            respostas.push(MessagesConstants.ENDERECO_NAO_ENCONTRADO(hint));
            return;
        }
        await this._applyRoute(parseFloat(geoResult.lat), parseFloat(geoResult.lon), addressToGeocode);
    }
    async _handleAddressNumber() {
        const numberInput = texto.trim();
        let streetInfo = {};
        try {
            streetInfo = JSON.parse(newCart.address_street_temp || '{}');
        }
        catch (error) { }
        if (!streetInfo['localidade']) {
            newState = BotState.AWAITING_ADDRESS;
            respostas.push(MessagesConstants.ENDERECO_INVALIDO_RETRY(estCity || ''));
            return;
        }
        const numLabel = numberInput === 's/n' ? 'S/N' : numberInput;
        const fullAddress = [streetInfo['logradouro'], numLabel, streetInfo['bairro'], streetInfo['localidade'], streetInfo['uf']].filter(Boolean).join(', ');
        newCart.address_street_temp = null;
        const geoResult = await geocodingProvider.search(fullAddress + ', Brasil');
        if (!geoResult) {
            const { total: cartSubtotal } = cartSummary(newCart.items);
            const fee = calcDeliveryFee(0, 0, cartSubtotal);
            const mapsLink = 'https://maps.google.com/?q=' + encodeURIComponent(fullAddress);
            newCart.address = fullAddress;
            newCart.delivery_fee = fee;
            const feeMsg = fee === 0 ? MessagesConstants.FRETE_GRATIS : MessagesConstants.TAXA_ENTREGA(fmtBRL(fee));
            newState = BotState.AWAITING_COMPLEMENT;
            respostas.push(MessagesConstants.ENDERECO_CONFIRMADO_CEP(fullAddress, mapsLink, feeMsg));
            return;
        }
        await this._applyRoute(parseFloat(geoResult.lat), parseFloat(geoResult.lon), fullAddress);
    }
}


class PaymentHandler extends BaseHandler {
    async handle() {
        if (currentState === BotState.AWAITING_MIXED_METHOD) {
            return this._handleMixedMethod();
        }
        if (currentState === BotState.AWAITING_MIXED_AMOUNT) {
            return this._handleMixedAmount();
        }
        if (currentState === BotState.AWAITING_SPLIT_COUNT) {
            return this._handleSplitCount();
        }
        if (currentState === BotState.AWAITING_SPLIT_PAYMENT) {
            return this._handleSplitPayment();
        }
        if (currentState === BotState.AWAITING_SPLIT_CHANGE) {
            return this._handleSplitChange();
        }
        if (currentState === BotState.AWAITING_MIXED_CHANGE) {
            return this._handleMixedChange();
        }
        if (currentState === BotState.AWAITING_PAYMENT) {
            return this._handlePayment();
        }
        if (currentState === BotState.AWAITING_CHANGE) {
            return this._handleChange();
        }
        return false;
    }
    _nonCashTypes() {
        return paymentTypes.filter((paymentType) => paymentType.name !== 'dinheiro');
    }
    _resolveOrderTypeLabel() {
        return (orderTypes.find((orderType) => orderType.name === newCart.order_type) || { label: 'Retirada' }).label;
    }
    _buildDeliveryLines() {
        const addrFull = newCart.address + (newCart.complement ? ', ' + newCart.complement : '');
        const mapsLine = newCart.order_type === 'delivery' ? MessagesConstants.MAPS_LINE(addrFull) : '';
        const typeLabel = newCart.order_type === 'delivery'
            ? MessagesConstants.ENTREGA_LABEL(addrFull, mapsLine)
            : '🏃 *' + this._resolveOrderTypeLabel() + '*';
        const feeLine = newCart.delivery_fee > 0
            ? MessagesConstants.ENTREGA_LINE(fmtBRL(newCart.delivery_fee))
            : MessagesConstants.FRETE_LINE;
        return { typeLabel, feeLine, addrFull };
    }
    _finalizeOrder(total, paymentName, paymentMethodLabel, changeFor) {
        const orderCode = generateOrderCode(tel);
        const { lines, total: subtotal } = cartSummary(newCart.items);
        const { typeLabel, feeLine, addrFull } = this._buildDeliveryLines();
        respostas.push(MessagesConstants.PEDIDO_CONFIRMADO_PREFIX
            + lines.join('\n')
            + '\n\n' + MessagesConstants.SUBTOTAL_LINE(fmtBRL(subtotal))
            + feeLine
            + '\n' + MessagesConstants.TOTAL_LINE(fmtBRL(total))
            + '\n\n' + typeLabel
            + MessagesConstants.PAGAMENTO_LINE(paymentMethodLabel, paymentEmoji(paymentName))
            + (changeFor ? MessagesConstants.TROCO_LINE(fmtBRL(changeFor)) : '')
            + MessagesConstants.PEDIDO_CODIGO(orderCode));
        save_order = true;
        finalOrder = {
            tel,
            customer_name: customerName,
            code: orderCode,
            items: newCart.items,
            subtotal,
            delivery_fee: newCart.delivery_fee,
            total,
            order_type: newCart.order_type,
            address: newCart.order_type === 'delivery' ? addrFull : '',
            maps_link: newCart.order_type === 'delivery' ? ('https://maps.google.com/?q=' + encodeURIComponent(addrFull)) : '',
            payment_method: paymentMethodLabel,
            change_for: changeFor,
        };
        newState = BotState.START;
        newCart = CartConstants.EMPTY();
        maybeAskOptIn();
    }
    _handleMixedMethod() {
        const nonCashTypes = this._nonCashTypes();
        let choiceIndex = parseInt(texto) - 1;
        if (isNaN(choiceIndex) || choiceIndex < 0)
            choiceIndex = nonCashTypes.findIndex((paymentType) => paymentType.name === texto);
        if (choiceIndex >= 0 && choiceIndex < nonCashTypes.length) {
            newCart.mixed_method = nonCashTypes[choiceIndex].name;
            newCart.mixed_label = nonCashTypes[choiceIndex].label;
            const { total: subtotal } = cartSummary(newCart.items);
            const total = subtotal + newCart.delivery_fee;
            newState = BotState.AWAITING_MIXED_AMOUNT;
            respostas.push(MessagesConstants.MISTO_VALOR(fmtBRL(total), nonCashTypes[choiceIndex].label));
        }
        else {
            respostas.push(MessagesConstants.OPCAO_INVALIDA + '\n\n' + nonCashOptions() + MessagesConstants.DIGITAR_NUMERO);
        }
        return true;
    }
    _handleMixedAmount() {
        const entered = parseFloat(texto.replace(',', '.'));
        const { total: subtotal } = cartSummary(newCart.items);
        const total = subtotal + newCart.delivery_fee;
        if (isNaN(entered) || entered <= 0) {
            respostas.push(MessagesConstants.MISTO_VALOR_INVALIDO(newCart.mixed_label || 'cartão'));
        }
        else if (entered >= total) {
            respostas.push(MessagesConstants.MISTO_VALOR_EXCEDE(newCart.mixed_label || 'cartão', fmtBRL(entered), fmtBRL(total)));
        }
        else {
            newCart.mixed_amount = entered;
            const cashPart = total - entered;
            newState = BotState.AWAITING_MIXED_CHANGE;
            respostas.push(MessagesConstants.MISTO_PARTE_DINHEIRO(fmtBRL(cashPart)));
        }
        return true;
    }
    _handleSplitCount() {
        const splitCount = parseInt(texto);
        if (!splitCount || splitCount < 2 || splitCount > 30) {
            respostas.push(MessagesConstants.DIVIDIR_INVALIDO);
        }
        else {
            newCart.split_count = splitCount;
            newCart.split_current = 1;
            newCart.split_payments = [];
            const { total: subtotal } = cartSummary(newCart.items);
            const total = subtotal + newCart.delivery_fee;
            const perPerson = fmtBRL(total / splitCount);
            newState = BotState.AWAITING_SPLIT_PAYMENT;
            respostas.push(splitPersonPaymentList(1, splitCount, perPerson));
        }
        return true;
    }
    _handleSplitPayment() {
        let choiceIndex = parseInt(texto) - 1;
        if (isNaN(choiceIndex) || choiceIndex < 0)
            choiceIndex = paymentTypes.findIndex((paymentType) => paymentType.name === texto);
        const { total: subtotal } = cartSummary(newCart.items);
        const total = subtotal + newCart.delivery_fee;
        const splitTotal = newCart.split_count;
        const perPerson = total / splitTotal;
        if (choiceIndex < 0 || choiceIndex >= paymentTypes.length) {
            respostas.push(splitPersonPaymentList(newCart.split_current, splitTotal, fmtBRL(perPerson)));
            return true;
        }
        const selectedPayment = paymentTypes[choiceIndex];
        if (selectedPayment.name === 'dinheiro') {
            newCart.payment_method = 'dinheiro';
            newState = BotState.AWAITING_SPLIT_CHANGE;
            respostas.push(MessagesConstants.DIVIDIR_TROCO(newCart.split_current, fmtBRL(perPerson)));
        }
        else {
            const payments = Array.isArray(newCart.split_payments) ? newCart.split_payments : [];
            payments.push({ person: newCart.split_current, label: paymentEmoji(selectedPayment.name) + ' ' + selectedPayment.label, change_for: null });
            newCart.split_payments = payments;
            if (newCart.split_current >= splitTotal) {
                this._finalizeSplitOrder(total, subtotal, splitTotal, perPerson, payments);
            }
            else {
                newCart.split_current = newCart.split_current + 1;
                newState = BotState.AWAITING_SPLIT_PAYMENT;
                respostas.push(splitPersonPaymentList(newCart.split_current, splitTotal, fmtBRL(perPerson)));
            }
        }
        return true;
    }
    _handleSplitChange() {
        const { total: subtotal } = cartSummary(newCart.items);
        const total = subtotal + newCart.delivery_fee;
        const splitTotal = newCart.split_count;
        const perPerson = total / splitTotal;
        let changeFor = null;
        if (texto !== 'não' && texto !== 'nao') {
            const changeValue = parseTrocoInput(texto, perPerson);
            if (changeValue === null || changeValue <= perPerson) {
                respostas.push(MessagesConstants.DIVIDIR_TROCO_INVALIDO(fmtBRL(perPerson)));
                _earlyResponse = buildPayload();
                return true;
            }
            changeFor = changeValue;
        }
        const payments = Array.isArray(newCart.split_payments) ? newCart.split_payments : [];
        payments.push({ person: newCart.split_current, label: '💵 Dinheiro', change_for: changeFor });
        newCart.split_payments = payments;
        if (newCart.split_current >= splitTotal) {
            this._finalizeSplitOrder(total, subtotal, splitTotal, perPerson, payments);
        }
        else {
            newCart.split_current = newCart.split_current + 1;
            newState = BotState.AWAITING_SPLIT_PAYMENT;
            respostas.push(splitPersonPaymentList(newCart.split_current, splitTotal, fmtBRL(perPerson)));
        }
        return true;
    }
    _finalizeSplitOrder(total, subtotal, splitTotal, perPerson, payments) {
        const orderCode = generateOrderCode(tel);
        const { typeLabel, feeLine, addrFull } = this._buildDeliveryLines();
        const splitLines = payments.map((splitPayment) => MessagesConstants.SPLIT_PERSON_LINE(splitPayment.person, splitPayment.label, splitPayment.change_for ? fmtBRL(splitPayment.change_for) : null)).join('\n');
        respostas.push(MessagesConstants.PEDIDO_CONFIRMADO_PREFIX
            + cartSummary(newCart.items).lines.join('\n')
            + '\n\n' + MessagesConstants.SUBTOTAL_LINE(fmtBRL(subtotal))
            + feeLine
            + '\n' + MessagesConstants.TOTAL_LINE(fmtBRL(total))
            + '\n\n' + typeLabel
            + MessagesConstants.DIVISAO_HEADER(splitTotal, fmtBRL(perPerson))
            + splitLines
            + MessagesConstants.PEDIDO_CODIGO(orderCode));
        save_order = true;
        finalOrder = {
            tel,
            customer_name: customerName,
            code: orderCode,
            items: newCart.items,
            subtotal,
            delivery_fee: newCart.delivery_fee,
            total,
            order_type: newCart.order_type,
            address: newCart.order_type === 'delivery' ? addrFull : '',
            maps_link: newCart.order_type === 'delivery' ? ('https://maps.google.com/?q=' + encodeURIComponent(addrFull)) : '',
            payment_method: 'dividido: ' + payments.map((splitPayment) => splitPayment.label).join(', '),
            change_for: null,
            split_count: splitTotal,
            split_payments: payments,
        };
        newState = BotState.START;
        newCart = CartConstants.EMPTY();
        maybeAskOptIn();
    }
    _handleMixedChange() {
        const { total: subtotal } = cartSummary(newCart.items);
        const total = subtotal + newCart.delivery_fee;
        const entered = newCart.mixed_amount;
        const cashPart = total - entered;
        let changeFor = null;
        if (texto !== 'não' && texto !== 'nao') {
            const changeValue = parseTrocoInput(texto, cashPart);
            if (changeValue === null || changeValue <= cashPart) {
                respostas.push(MessagesConstants.DIVIDIR_TROCO_INVALIDO(fmtBRL(cashPart)));
                _earlyResponse = buildPayload();
                return true;
            }
            changeFor = changeValue;
        }
        const orderCode = generateOrderCode(tel);
        const { typeLabel, feeLine, addrFull } = this._buildDeliveryLines();
        const changeInfo = changeFor ? ' _(troco p/ R$ ' + fmtBRL(changeFor) + ')_' : '';
        respostas.push(MessagesConstants.PEDIDO_CONFIRMADO_PREFIX
            + cartSummary(newCart.items).lines.join('\n')
            + '\n\n' + MessagesConstants.SUBTOTAL_LINE(fmtBRL(subtotal))
            + feeLine
            + '\n' + MessagesConstants.TOTAL_LINE(fmtBRL(total))
            + '\n\n' + typeLabel
            + '\n' + paymentEmoji(newCart.mixed_method || '') + ' *' + (newCart.mixed_label || 'Cartão') + ':* R$ ' + fmtBRL(entered)
            + '\n💵 *Dinheiro:* R$ ' + fmtBRL(cashPart) + changeInfo
            + MessagesConstants.PEDIDO_CODIGO(orderCode));
        save_order = true;
        finalOrder = {
            tel, customer_name: customerName, code: orderCode, items: newCart.items,
            subtotal, delivery_fee: newCart.delivery_fee, total, order_type: newCart.order_type,
            address: newCart.order_type === 'delivery' ? addrFull : '',
            maps_link: newCart.order_type === 'delivery' ? ('https://maps.google.com/?q=' + encodeURIComponent(addrFull)) : '',
            payment_method: (newCart.mixed_label || 'misto') + ' + dinheiro',
            change_for: changeFor,
        };
        newState = BotState.START;
        newCart = CartConstants.EMPTY();
        maybeAskOptIn();
        return true;
    }
    _handlePayment() {
        let choiceIndex = parseInt(texto) - 1;
        if (isNaN(choiceIndex) || choiceIndex < 0)
            choiceIndex = paymentTypes.findIndex((paymentType) => paymentType.name === texto);
        if (choiceIndex >= 0 && choiceIndex < paymentTypes.length) {
            const selectedPayment = paymentTypes[choiceIndex];
            newCart.payment_method = selectedPayment.name;
            const { total: subtotal } = cartSummary(newCart.items);
            const total = subtotal + newCart.delivery_fee;
            if (selectedPayment.name === 'dinheiro') {
                newState = BotState.AWAITING_CHANGE;
                respostas.push(MessagesConstants.PAGAMENTO_DINHEIRO(fmtBRL(total)));
            }
            else {
                const pixInfo = (selectedPayment.name === 'pix' && pixKey)
                    ? MessagesConstants.PIX_INFO(pixKey, pixName)
                    : '';
                const splitLine = newCart.split_count > 1
                    ? MessagesConstants.SPLIT_LINE(newCart.split_count, fmtBRL(total / newCart.split_count))
                    : '';
                const orderCode = generateOrderCode(tel);
                const { typeLabel, feeLine, addrFull } = this._buildDeliveryLines();
                respostas.push(MessagesConstants.PEDIDO_CONFIRMADO_PREFIX
                    + cartSummary(newCart.items).lines.join('\n')
                    + '\n\n' + MessagesConstants.SUBTOTAL_LINE(fmtBRL(subtotal))
                    + feeLine
                    + '\n' + MessagesConstants.TOTAL_LINE(fmtBRL(total))
                    + splitLine
                    + '\n\n' + typeLabel
                    + MessagesConstants.PAGAMENTO_LINE(selectedPayment.label, paymentEmoji(selectedPayment.name))
                    + pixInfo
                    + MessagesConstants.PEDIDO_CODIGO(orderCode));
                save_order = true;
                finalOrder = {
                    tel, customer_name: customerName, code: orderCode, items: newCart.items,
                    subtotal, delivery_fee: newCart.delivery_fee, total, order_type: newCart.order_type,
                    address: newCart.order_type === 'delivery' ? addrFull : '',
                    maps_link: newCart.order_type === 'delivery' ? ('https://maps.google.com/?q=' + encodeURIComponent(addrFull)) : '',
                    payment_method: selectedPayment.name,
                    change_for: null,
                };
                newState = BotState.START;
                newCart = CartConstants.EMPTY();
                maybeAskOptIn();
            }
            return true;
        }
        if (texto === 'dividir' || parseInt(texto) === paymentTypes.length + 1 || texto.toLowerCase().includes('dividir')) {
            newState = BotState.AWAITING_SPLIT_COUNT;
            respostas.push(MessagesConstants.DIVIDIR_CONTA);
            return true;
        }
        if (texto === 'misto' || parseInt(texto) === paymentTypes.length + 2 || texto.toLowerCase().includes('misto')) {
            const nonCashTypes = this._nonCashTypes();
            if (nonCashTypes.length === 0) {
                respostas.push(MessagesConstants.SEM_FORMAS_MISTO);
            }
            else if (nonCashTypes.length === 1) {
                newCart.mixed_method = nonCashTypes[0].name;
                newCart.mixed_label = nonCashTypes[0].label;
                const { total: subtotal } = cartSummary(newCart.items);
                const total = subtotal + newCart.delivery_fee;
                newState = BotState.AWAITING_MIXED_AMOUNT;
                respostas.push(MessagesConstants.MISTO_VALOR(fmtBRL(total), nonCashTypes[0].label));
            }
            else {
                newState = BotState.AWAITING_MIXED_METHOD;
                respostas.push(MessagesConstants.MISTO_ESCOLHER_METODO(nonCashOptions()));
            }
            return true;
        }
        respostas.push(paymentList(newCart.split_count));
        return true;
    }
    _handleChange() {
        const { total: subtotal } = cartSummary(newCart.items);
        const total = subtotal + newCart.delivery_fee;
        let changeValue = null;
        if (texto !== 'não' && texto !== 'nao') {
            changeValue = parseTrocoInput(texto, total);
            if (changeValue === null || changeValue <= total) {
                respostas.push(MessagesConstants.TROCO_INVALIDO(fmtBRL(total)));
                _earlyResponse = buildPayload();
                return true;
            }
        }
        this._finalizeOrder(total, 'dinheiro', 'Dinheiro', changeValue);
        return true;
    }
}


