class ReservationHandler extends BaseHandler {
    async handle() {
        if (currentState === BotState.RESERVING) {
            return this._handleReserving();
        }
        if (currentState === BotState.CONFIRMING_RESERVATION && texto === 'sim') {
            return this._handleConfirmReservation();
        }
        if (currentState === BotState.CONFIRMING_RESERVATION && (texto === 'não' || texto === 'nao')) {
            newReservationTemp = {};
            newState = BotState.START;
            respostas.push(MessagesConstants.RESERVA_CANCELADA);
            respostas.push(mainMenu());
            return true;
        }
        return false;
    }
    _handleReserving() {
        const dateValue = parseDate(texto);
        const timeValue = parseTime(texto);
        const sizeValue = parsePeople(texto);
        const missing = [];
        if (!dateValue)
            missing.push('📆 data');
        if (!timeValue)
            missing.push('🕗 horário');
        if (!sizeValue)
            missing.push('👥 número de pessoas');
        if (missing.length > 0) {
            respostas.push(MessagesConstants.RESERVA_FALTANDO(missing.join(', ')));
            return true;
        }
        const timeStr = timeValue + ':00';
        const availableTables = restaurantTables
            .filter((table) => table.capacity >= sizeValue)
            .filter((table) => !upcomingReservations.some((reservation) => reservation.date === dateValue && reservation.time === timeStr && reservation.table_id === table.id))
            .sort((tableA, tableB) => tableA.capacity - tableB.capacity);
        if (availableTables.length === 0) {
            respostas.push(MessagesConstants.RESERVA_SEM_MESA(sizeValue, fmtDate(dateValue), timeValue));
        }
        else {
            const selectedTable = availableTables[0];
            newReservationTemp = { date: dateValue, time: timeValue, party_size: sizeValue, table_id: selectedTable.id, table_number: selectedTable.number };
            newState = BotState.CONFIRMING_RESERVATION;
            respostas.push(confirmBtn(MessagesConstants.RESERVA_RESUMO(fmtDate(dateValue), timeValue, sizeValue, selectedTable.number)));
        }
        return true;
    }
    _handleConfirmReservation() {
        const reservationData = newReservationTemp;
        if (!reservationData || !reservationData.date) {
            newState = BotState.START;
            respostas.push(MessagesConstants.RESERVA_DADOS_INVALIDOS);
            return true;
        }
        save_reservation = true;
        finalReservation = {
            tel,
            date: reservationData.date,
            time: reservationData.time,
            party_size: reservationData.party_size,
            table_id: reservationData.table_id,
        };
        newReservationTemp = {};
        newState = BotState.START;
        const estabAddr = estAddress;
        const mapsLink = estabAddr ? MessagesConstants.RESERVA_MAPS_LINE(estabAddr) : '';
        const addrLine = estabAddr ? MessagesConstants.RESERVA_ADDR_LINE(estabAddr, mapsLink) : '';
        respostas.push(MessagesConstants.RESERVA_CONFIRMADA(fmtDate(reservationData.date), reservationData.time, reservationData.party_size, reservationData.table_number, addrLine));
        return true;
    }
}


class MiscHandler extends BaseHandler {
    async handle() {
        // Atalhos de navegação (protegidos por !expectingRawInput)
        if (!expectingRawInput && (texto === '5' || texto.startsWith('meu pedido') || texto.startsWith('meus pedido') || texto === 'pedidos')) {
            return this._handleMyOrders();
        }
        if (!expectingRawInput && (texto === '4' || texto.includes('atendente') || texto.includes('humano'))) {
            newState = BotState.HUMAN_HANDOFF;
            create_chatwoot_conversation = true;
            chatwootCustomerName = customerName || '';
            respostas.push(MessagesConstants.CONECTANDO_ATENDENTE);
            return true;
        }
        if (!expectingRawInput && (texto === '6' || texto === 'notificacoes' || texto === 'notificações')) {
            respostas.push(notifBtn(marketingOptIn));
            newState = BotState.NOTIFICATIONS_MENU;
            return true;
        }
        if (!expectingRawInput && (texto === '0' || texto === 'voltar')) {
            newState = BotState.START;
            respostas.push(MessagesConstants.VOLTAR_MENU);
            respostas.push(mainMenu());
            return true;
        }
        // Estados de atendimento humano e pedido
        if (currentState === BotState.HUMAN_HANDOFF) {
            respostas.push(MessagesConstants.EM_ATENDIMENTO_HUMANO);
            return true;
        }
        if (currentState === BotState.AWAITING_ORDER_DETAIL) {
            return this._handleOrderDetail();
        }
        if (currentState === BotState.NOTIFICATIONS_MENU) {
            return this._handleNotificationsMenu();
        }
        if (currentState === BotState.AWAITING_NAME) {
            return this._handleName();
        }
        if (currentState === BotState.AWAITING_COMPLEMENT) {
            if (texto === 'ok' || texto === 'nao' || texto === 'não' || texto === 'sem complemento') {
                newCart.complement = '';
            }
            else {
                newCart.complement = texto.trim();
            }
            newState = BotState.AWAITING_PAYMENT;
            respostas.push(paymentList(newCart.split_count));
            return true;
        }
        // Keyword handlers — status do último pedido
        if (texto === 'status' || texto === 'meu pedido' || texto === 'pedido') {
            return this._handleLastOrderStatus();
        }
        // Keyword handlers — notificações inline
        if (texto === 'notificações' || texto === 'notificacoes' || texto === 'promoções' || texto === 'promocoes') {
            return this._handleNotifInfo();
        }
        if (texto.includes('desativar notifica') || texto.includes('desativar promoç')) {
            save_marketing_opt_in = true;
            marketing_opt_in_value = false;
            respostas.push(MessagesConstants.NOTIF_DESATIVADAS_OK);
            return true;
        }
        if (texto.includes('ativar notifica') || texto.includes('ativar promoç')) {
            save_marketing_opt_in = true;
            marketing_opt_in_value = true;
            respostas.push(MessagesConstants.NOTIF_ATIVADAS_OK);
            return true;
        }
        if (currentState === BotState.AWAITING_MARKETING_OPT_IN) {
            return this._handleMarketingOptIn();
        }
        return false;
    }
    _statusLabel(status, orderType) {
        const isDelivery = orderType === 'delivery';
        const statusMap = {
            received: MessagesConstants.STATUS_MAP.received,
            confirmed: MessagesConstants.STATUS_MAP.confirmed,
            preparing: MessagesConstants.STATUS_MAP.preparing,
            ready: isDelivery ? MessagesConstants.STATUS_MAP.ready_delivery : MessagesConstants.STATUS_MAP.ready_pickup,
            out_for_delivery: MessagesConstants.STATUS_MAP.out_for_delivery,
            delivered: MessagesConstants.STATUS_MAP.delivered,
            cancelled: MessagesConstants.STATUS_MAP.cancelled,
        };
        return statusMap[status] || status;
    }
    _handleMyOrders() {
        if (!recentOrders || recentOrders.length === 0) {
            respostas.push(MessagesConstants.SEM_PEDIDOS);
            return true;
        }
        let msg = MessagesConstants.PEDIDOS_HEADER;
        recentOrders.forEach((order, index) => {
            const statusText = this._statusLabel(order.status, order.order_type);
            const tipoLabel = order.order_type === 'delivery'
                ? MessagesConstants.PEDIDO_DETALHE_TIPO_DELIVERY
                : order.order_type === 'retirada'
                    ? MessagesConstants.PEDIDO_DETALHE_TIPO_RETIRADA
                    : MessagesConstants.PEDIDO_DETALHE_TIPO_MESA;
            msg += '*' + (index + 1) + '. #' + order.code + '*\n'
                + '   ' + tipoLabel + ' — R$ ' + fmtBRL(order.total) + '\n'
                + '   ' + statusText + ' — ' + order.created_at + '\n\n';
        });
        msg += MessagesConstants.PEDIDOS_FOOTER;
        respostas.push(msg);
        newState = BotState.AWAITING_ORDER_DETAIL;
        return true;
    }
    _handleOrderDetail() {
        const codeInput = texto.replace(/^#/, '').toUpperCase();
        const foundOrder = recentOrders.find((order) => order.code.toUpperCase() === codeInput);
        if (foundOrder) {
            const tipoLabel = foundOrder.order_type === 'delivery'
                ? MessagesConstants.PEDIDO_DETALHE_TIPO_DELIVERY
                : foundOrder.order_type === 'retirada'
                    ? MessagesConstants.PEDIDO_DETALHE_TIPO_RETIRADA
                    : MessagesConstants.PEDIDO_DETALHE_TIPO_MESA;
            const statusText = this._statusLabel(foundOrder.status, foundOrder.order_type);
            respostas.push(MessagesConstants.PEDIDO_DETALHE_HEADER(foundOrder.code)
                + tipoLabel + ' — R$ ' + fmtBRL(foundOrder.total) + '\n'
                + statusText + ' — ' + foundOrder.created_at + '\n'
                + (foundOrder.payment_method ? '💳 ' + foundOrder.payment_method + '\n' : '')
                + '\n_' + (foundOrder.items_count || 0) + ' item(s)_\n\n'
                + MessagesConstants.PEDIDO_DETALHE_FOOTER);
        }
        else if (texto === '0' || texto === 'voltar' || texto === 'menu') {
            newState = BotState.START;
            respostas.push(MessagesConstants.VOLTAR_MENU);
            respostas.push(mainMenu());
        }
        else {
            respostas.push(MessagesConstants.PEDIDO_CODIGO_NAO_ENCONTRADO(texto));
        }
        return true;
    }
    _handleNotificationsMenu() {
        if (texto === 'ativar' || texto === 'sim') {
            save_marketing_opt_in = true;
            marketing_opt_in_value = true;
            newState = BotState.START;
            respostas.push(MessagesConstants.NOTIF_ATIVADAS);
            respostas.push(mainMenu());
        }
        else if (texto === 'desativar' || texto === 'nao' || texto === 'não') {
            save_marketing_opt_in = true;
            marketing_opt_in_value = false;
            newState = BotState.START;
            respostas.push(MessagesConstants.NOTIF_DESATIVADAS);
            respostas.push(mainMenu());
        }
        else if (texto === '0' || texto === 'voltar') {
            newState = BotState.START;
            respostas.push('🔙 ');
            respostas.push(mainMenu());
        }
        else {
            respostas.push(MessagesConstants.NOTIF_MENU_PROMPT);
        }
        return true;
    }
    _handleName() {
        const validation = validateName(texto);
        if (!validation.valid) {
            respostas.push(validation.reason === 'bad_word'
                ? MessagesConstants.NOME_INVALIDO_PALAVRAO
                : MessagesConstants.NOME_INVALIDO_GENERICO);
            newState = BotState.AWAITING_NAME;
            return true;
        }
        const nameFormatted = capitalizeName(texto);
        customerNameToSave = nameFormatted;
        save_customer_name = true;
        newState = BotState.START;
        if (lastOrder && Array.isArray(lastOrder.items) && lastOrder.items.length > 0) {
            const lines = buildRepeatOrderLines({ lastOrder, products, header: '🔄 *Seu último pedido foi:*' });
            newState = BotState.REPEAT_ORDER;
            respostas.push(MessagesConstants.SAUDACAO_APOS_NOME(nameFormatted) + msgWelcome);
            respostas.push(lines.join('\n'));
            respostas.push(yesNo(MessagesConstants.SAUDACAO_REPEAT_PERGUNTA));
        }
        else {
            respostas.push(MessagesConstants.SAUDACAO_APOS_NOME(nameFormatted) + msgWelcome);
            respostas.push(mainMenu());
        }
        return true;
    }
    _handleLastOrderStatus() {
        if (!lastOrder || !lastOrder.code) {
            respostas.push('Nenhum pedido encontrado. 😊\n\nDigite *2* para fazer seu primeiro pedido!');
            return true;
        }
        const statusMap = {
            received: '📥 Recebido', confirmed: '✅ Confirmado', preparing: '👨‍🍳 Em preparo',
            ready: '✅ Pronto para entrega', delivered: '🚀 Entregue', cancelled: '❌ Cancelado',
        };
        const statusLabel = statusMap[lastOrder.status || ''] || lastOrder.status || '📥 Recebido';
        const { lines } = cartSummary(lastOrder.items || []);
        respostas.push('📋 *Seu último pedido:*\n\n🔖 Código: *' + lastOrder.code + '*\n\n' + lines.join('\n') + '\n\n*Total: R$ ' + fmtBRL(lastOrder.total) + '*\n\nStatus: ' + statusLabel);
        return true;
    }
    _handleNotifInfo() {
        if (marketingOptIn === true) {
            respostas.push(MessagesConstants.NOTIF_ATIVAS_INFO);
        }
        else if (marketingOptIn === false) {
            respostas.push(MessagesConstants.NOTIF_INATIVAS_INFO);
        }
        else {
            respostas.push(MessagesConstants.NOTIF_NAO_CONFIGURADAS);
        }
        return true;
    }
    _handleMarketingOptIn() {
        if (texto === 'sim') {
            save_marketing_opt_in = true;
            marketing_opt_in_value = true;
            newState = BotState.START;
            respostas.push(MessagesConstants.OPT_IN_SIM);
        }
        else if (texto === 'não' || texto === 'nao') {
            save_marketing_opt_in = true;
            marketing_opt_in_value = false;
            newState = BotState.START;
            respostas.push(MessagesConstants.OPT_IN_NAO);
        }
        else {
            respostas.push(MessagesConstants.OPT_IN_REPROMPT);
        }
        return true;
    }
}


class OrderingHandler extends BaseHandler {
    async handle() {
        if (currentState === BotState.BROWSING_CATEGORIES || currentState === BotState.ORDERING_CAT) {
            return this._handleCategories();
        }
        if (currentState === BotState.BROWSING_ITEMS || currentState === BotState.ORDERING_ITEMS) {
            return this._handleItems();
        }
        if (currentState === BotState.AWAITING_QTY) {
            return this._handleQuantity();
        }
        if (currentState === BotState.AWAITING_MORE) {
            return this._handleMore();
        }
        return false;
    }
    _handleCategories() {
        const catInput = texto.replace(/^(order_cat:|cat:)/, '');
        if (catInput === 'back' || texto === '0' || texto === 'voltar') {
            newState = BotState.START;
            respostas.push(mainMenu());
            return true;
        }
        const allCategories = [...new Set(products.map((product) => product.category || 'Outros'))];
        const foundCategory = allCategories.find((category) => category.toLowerCase() === catInput.toLowerCase());
        if (foundCategory) {
            newCart.browse_category = foundCategory;
            newState = BotState.ORDERING_ITEMS;
            respostas.push(itemsList(foundCategory, 'order', 0));
        }
        else {
            respostas.push(categoryList('order'));
        }
        return true;
    }
    _handleItems() {
        const currentCategory = newCart.browse_category || '';
        if (texto === 'cat:back' || texto === 'order_cat:back' || texto === '0' || texto === 'voltar') {
            newState = BotState.ORDERING_CAT;
            respostas.push(categoryList('order'));
            return true;
        }
        if (texto.startsWith('page:')) {
            const pageParts = texto.split(':');
            const pageContext = pageParts[1];
            const pageCategoryRaw = pageParts.slice(2, -1).join(':');
            const pageNumber = parseInt(pageParts[pageParts.length - 1]);
            const resolvedCategory = products.map((product) => product.category || 'Outros')
                .find((category) => category.toLowerCase() === pageCategoryRaw.toLowerCase()) || pageCategoryRaw;
            respostas.push(itemsList(resolvedCategory, pageContext, pageNumber));
            return true;
        }
        const allCategoryItems = products.filter((product) => (product.category || 'Outros') === currentCategory);
        const PAGE_SIZE = 9;
        const currentPage = newCart.browse_page || 0;
        const pageStart = currentPage * PAGE_SIZE;
        if (texto === 'próxima' || texto === 'proxima' || texto === 'próximo' || texto === 'proximo') {
            if (allCategoryItems.length > pageStart + PAGE_SIZE) {
                newCart.browse_page = currentPage + 1;
                respostas.push(itemsList(currentCategory, 'order', currentPage + 1));
            }
            else {
                respostas.push(itemsList(currentCategory, 'order', 0));
            }
            return true;
        }
        const itemNumber = parseInt(texto);
        if (!isNaN(itemNumber) && itemNumber >= 1 && itemNumber <= allCategoryItems.length) {
            const selectedProduct = allCategoryItems[itemNumber - 1];
            newCart.pending_item_id = selectedProduct.id;
            newCart.pending_item_name = selectedProduct.name;
            newCart.browse_page = 0;
            newState = BotState.AWAITING_QTY;
            const descriptionText = selectedProduct.description ? '\n_' + selectedProduct.description + '_' : '';
            respostas.push({
                type: 'buttons',
                body: '🛒 *' + selectedProduct.name + '*\nR$ ' + fmtBRL(selectedProduct.price) + descriptionText,
                buttons: [
                    { id: 'qty:1', title: '✅ Adicionar (1un)' },
                    { id: 'qty:more', title: '✏️ Outra qtd' },
                    { id: 'item:back', title: '↩️ Voltar' },
                ],
            });
        }
        else {
            respostas.push(itemsList(currentCategory, 'order', currentPage));
        }
        return true;
    }
    _handleQuantity() {
        if (texto === 'item:back') {
            newState = BotState.ORDERING_ITEMS;
            respostas.push(itemsList(newCart.browse_category || '', 'order', newCart.browse_page || 0));
            return true;
        }
        if (texto === 'qty:more') {
            respostas.push(MessagesConstants.QTD_SOLICITAR);
            return true;
        }
        let quantity = null;
        if (texto.startsWith('qty:')) {
            quantity = parseInt(texto.replace('qty:', ''));
        }
        else {
            const parsed = parseInt(texto);
            if (!isNaN(parsed) && parsed >= 1 && parsed <= 99)
                quantity = parsed;
        }
        if (!quantity || quantity < 1) {
            respostas.push({
                type: 'buttons',
                body: MessagesConstants.QTD_INVALIDA,
                buttons: [{ id: 'qty:1', title: '✅ Adicionar (1un)' }, { id: 'item:back', title: '↩️ Voltar' }],
            });
            return true;
        }
        const foundProduct = products.find((product) => String(product.id) === String(newCart.pending_item_id));
        if (!foundProduct) {
            newState = BotState.START;
            respostas.push(mainMenu());
            return true;
        }
        const existingItem = newCart.items.find((cartItem) => cartItem.id === foundProduct.id);
        if (existingItem) {
            existingItem.qty += quantity;
        }
        else {
            newCart.items.push({ id: foundProduct.id, name: foundProduct.name, qty: quantity, price: Number(foundProduct.price), menuIdx: products.indexOf(foundProduct) + 1 });
        }
        newCart.pending_item_id = null;
        newCart.pending_item_name = '';
        const { lines: cartLines, total } = cartSummary(newCart.items);
        newState = BotState.AWAITING_MORE;
        respostas.push({
            type: 'buttons',
            body: MessagesConstants.ITEM_ADICIONADO(foundProduct.name, quantity)
                + '\n\n🛒 *Carrinho:*\n' + cartLines.join('\n')
                + '\n\n' + MessagesConstants.TOTAL_PARCIAL(fmtBRL(total))
                + '\n\nDeseja adicionar mais itens ou finalizar?',
            buttons: [{ id: '__add_more__', title: '➕ Adicionar mais' }, { id: 'finalizar', title: '✅ Finalizar' }],
        });
        return true;
    }
    _handleMore() {
        if (texto === '__add_more__') {
            const savedCategory = newCart.browse_category;
            newState = savedCategory ? BotState.ORDERING_ITEMS : BotState.ORDERING_CAT;
            respostas.push(savedCategory ? itemsList(savedCategory, 'order', 0) : categoryList('order'));
            return true;
        }
        if (texto === 'finalizar') {
            const { lines, total } = cartSummary(newCart.items);
            const minOrder = minOrderValue;
            if (minOrder > 0 && total < minOrder) {
                respostas.push(MessagesConstants.ORDEM_MINIMO_ADDMORE(fmtBRL(minOrder), fmtBRL(total)));
                newState = BotState.AWAITING_MORE;
                respostas.push({ type: 'buttons', body: 'Adicionar mais para atingir o mínimo?', buttons: [{ id: '__add_more__', title: '➕ Adicionar mais' }] });
            }
            else {
                newState = BotState.CONFIRMING;
                respostas.push(confirmBtn(MessagesConstants.CONFIRMAR_PEDIDO(lines.join('\n'), fmtBRL(total))));
            }
            return true;
        }
        respostas.push({ type: 'buttons', body: MessagesConstants.ADICIONAR_MAIS_PERGUNTA, buttons: [{ id: '__add_more__', title: '➕ Adicionar mais' }, { id: 'finalizar', title: '✅ Finalizar' }] });
        return true;
    }
}


class FallbackHandler extends BaseHandler {
    async handle() {
        const textLines = texto.split(/[\n,+]/).map((line) => line.trim()).filter(Boolean);
        const parsedItems = [];
        const unrecognizedLines = [];
        for (const line of textLines) {
            const indexQtyMatch = line.match(/^(\d+)\s*[xX×]\s*(\d+)$/);
            if (indexQtyMatch) {
                const productIndex = parseInt(indexQtyMatch[1]) - 1;
                const quantity = parseInt(indexQtyMatch[2]);
                if (quantity < 1) {
                    unrecognizedLines.push(line);
                    continue;
                }
                if (productIndex >= 0 && products && productIndex < products.length) {
                    const product = products[productIndex];
                    parsedItems.push({ id: product.id, name: product.name, qty: quantity, price: Number(product.price), menuIdx: productIndex + 1 });
                }
                else {
                    unrecognizedLines.push(line);
                }
                continue;
            }
            const nameQtyMatch = line.match(/^(.+?)\s*[xX×]\s*(\d+)$/);
            if (nameQtyMatch) {
                const normalize = (source) => source.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
                const searchTerm = normalize(nameQtyMatch[1].trim());
                const quantity = parseInt(nameQtyMatch[2]);
                const foundProduct = products && products.find((product) => normalize(product.name).includes(searchTerm));
                if (foundProduct && quantity >= 1) {
                    parsedItems.push({ id: foundProduct.id, name: foundProduct.name, qty: quantity, price: Number(foundProduct.price), menuIdx: products.indexOf(foundProduct) + 1 });
                }
                else {
                    unrecognizedLines.push(line);
                }
                continue;
            }
            const numberOnlyMatch = line.match(/^(\d+)$/);
            if (numberOnlyMatch) {
                const productNumber = parseInt(numberOnlyMatch[1]);
                if (productNumber >= 1 && products && productNumber <= products.length) {
                    const product = products[productNumber - 1];
                    parsedItems.push({ id: product.id, name: product.name, qty: 1, price: Number(product.price), menuIdx: productNumber });
                }
                else {
                    unrecognizedLines.push(line);
                }
            }
            else {
                unrecognizedLines.push(line);
            }
        }
        if (parsedItems.length > 0) {
            // Desduplicar itens da mesma mensagem
            const dedupedItems = [];
            for (const parsedItem of parsedItems) {
                const existingInDeduped = dedupedItems.find((deduped) => deduped.id === parsedItem.id);
                if (existingInDeduped) {
                    existingInDeduped.qty += parsedItem.qty;
                }
                else {
                    dedupedItems.push({ ...parsedItem });
                }
            }
            // Mergear com carrinho existente
            const hadItemsBefore = newCart.items.length > 0;
            for (const dedupedItem of dedupedItems) {
                const existingInCart = newCart.items.find((cartItem) => cartItem.id === dedupedItem.id);
                if (existingInCart) {
                    existingInCart.qty += dedupedItem.qty;
                }
                else {
                    newCart.items.push(dedupedItem);
                }
            }
            newState = BotState.ORDERING;
            const addedLines = dedupedItems.map((dedupedItem) => '• [' + (dedupedItem.menuIdx || '') + '] ' + dedupedItem.name + ' — R$ ' + fmtBRL(dedupedItem.price) + ' × ' + dedupedItem.qty + ' — R$ ' + fmtBRL(dedupedItem.price * dedupedItem.qty)).join('\n');
            const { lines: cartLines, total } = cartSummary(newCart.items);
            let msg = MessagesConstants.ADICIONAR_TEXTO + addedLines;
            if (hadItemsBefore) {
                msg += MessagesConstants.CARRINHO_ATUAL + cartLines.join('\n') + '\n' + MessagesConstants.TOTAL_LINE_SIMPLES(fmtBRL(total));
            }
            else {
                msg += MessagesConstants.TOTAL_PARCIAL(fmtBRL(total));
            }
            if (unrecognizedLines.length > 0)
                msg += MessagesConstants.NAO_RECONHECIDO(unrecognizedLines.join(', '));
            msg += MessagesConstants.INSTRUCOES_ORDERING;
            respostas.push(msg);
            return true;
        }
        if (currentState === BotState.START) {
            respostas.push(msgWelcome);
            respostas.push(mainMenu());
        }
        else {
            respostas.push(MessagesConstants.NAO_ENTENDI);
        }
        return true;
    }
}


