const token = $env.WHATSAPP_ACCESS_TOKEN;
const phoneId = $env.WHATSAPP_PHONE_NUMBER_ID;
const version = $env.WHATSAPP_API_VERSION || 'v21.0';
const url = `https://graph.facebook.com/${version}/${phoneId}/messages`;
const headers = { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` };

const buildPayload = (to, msg) => {
  if (typeof msg === 'string') {
    return { messaging_product: 'whatsapp', to, type: 'text', text: { body: msg } };
  }
  if (msg.type === 'buttons') {
    return {
      messaging_product: 'whatsapp', to, type: 'interactive',
      interactive: {
        type: 'button', body: { text: msg.body },
        action: { buttons: msg.buttons.slice(0,3).map(b => ({ type: 'reply', reply: { id: String(b.id), title: String(b.title).slice(0,20) } })) }
      }
    };
  }
  if (msg.type === 'list') {
    return {
      messaging_product: 'whatsapp', to, type: 'interactive',
      interactive: {
        type: 'list', body: { text: msg.body },
        action: { button: msg.button || 'Ver opções', sections: msg.sections }
      }
    };
  }
  if (msg.type === 'location') {
    return { messaging_product: 'whatsapp', to, type: 'location', location: { latitude: msg.latitude, longitude: msg.longitude, name: msg.name || '', address: msg.address || '' } };
  }
  if (msg.type === 'text_menu') {
    return { messaging_product: 'whatsapp', to, type: 'text', text: { body: msg.body } };
  }
  return { messaging_product: 'whatsapp', to, type: 'text', text: { body: typeof msg === 'object' && msg.body ? msg.body : String(msg) } };
};

const sent = [];
for (let i = 0; i < msgs.length; i++) {
  try {
    await this.helpers.httpRequest({ method: 'POST', url, headers, body: JSON.stringify(buildPayload(tel, msgs[i])) });
    sent.push(true);
  } catch(e) { sent.push({ error: e.message }); }
  if (i < msgs.length - 1) await new Promise(r => setTimeout(r, 800));
}
return [{ json: { ok: sent.every(s => s === true), tel, count: msgs.length, sent } }];

