// Step 1: Search for existing contact
let contactId;
try {
  const phoneSearch = tel.replace(/\D/g, '');
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: `${chatwootUrl}/api/v1/accounts/${accountId}/contacts/search?q=%2B${phoneSearch}&include_contacts=true`,
    headers: { 'api_access_token': apiToken }
  });
  const contacts = (res.payload || []);
  if (contacts.length > 0) {
    contactId = contacts[0].id;
    console.log('[chatwoot] Contato existente encontrado:', contactId);
  }
} catch(e) {
  console.log('[chatwoot] Erro ao buscar contato:', e.message);
}

// Step 2: Create contact if not found
if (!contactId) {
  try {
    const phoneE164 = '+' + tel.replace(/\D/g, '');
    const body = { name: customer_name || 'cliente', phone_number: phoneE164 };
    const created = await this.helpers.httpRequest({
      method: 'POST',
      url: `${chatwootUrl}/api/v1/accounts/${accountId}/contacts`,
      headers: { 'Content-Type': 'application/json', 'api_access_token': apiToken },
      body: JSON.stringify(body)
    });
    contactId = created.id;
    console.log('[chatwoot] Novo contato criado:', contactId);
  } catch(e) {
    console.log('[chatwoot] Erro ao criar contato:', e.message);
